type ledgerServer struct {
	UnimplementedTransactionServiceServer

	mu sync.Mutex

	// balances are stored in nanos of currency units: total = units*1e9 + nanos
	balances map[string]map[string]int64 // account -> currency -> nanos

	idem map[string]*Transaction // idempotency_key -> transaction
}

func newLedgerServer() *ledgerServer {
	return &ledgerServer{
		balances: make(map[string]map[string]int64),
		idem:     make(map[string]*Transaction),
	}
}

func (s *ledgerServer) CreateTransaction(ctx context.Context, req *CreateTransactionRequest) (*CreateTransactionResponse, error) {
	if req == nil || req.Amount == nil {
		return nil, status.Error(codes.InvalidArgument, "amount is required")
	}
	if req.FromAccountId == "" || req.ToAccountId == "" {
		return nil, status.Error(codes.InvalidArgument, "from_account_id and to_account_id are required")
	}
	if req.FromAccountId == req.ToAccountId {
		return nil, status.Error(codes.InvalidArgument, "from_account_id and to_account_id must differ")
	}
	if req.Amount.Currency == "" {
		return nil, status.Error(codes.InvalidArgument, "currency is required")
	}
	if err := validateMoney(req.Amount); err != nil {
		return nil, status.Error(codes.InvalidArgument, err.Error())
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	if req.IdempotencyKey != "" {
		if tx, ok := s.idem[req.IdempotencyKey]; ok {
			return &CreateTransactionResponse{Transaction: tx}, nil
		}
	}

	amtNanos := moneyToNanos(req.Amount)

	fromBal := s.getBalLocked(req.FromAccountId, req.Amount.Currency)
	if fromBal < amtNanos {
		return nil, status.Error(codes.FailedPrecondition, "insufficient funds")
	}

	s.setBalLocked(req.FromAccountId, req.Amount.Currency, fromBal-amtNanos)

	toBal := s.getBalLocked(req.ToAccountId, req.Amount.Currency)
	s.setBalLocked(req.ToAccountId, req.Amount.Currency, toBal+amtNanos)

	now := time.Now().UTC().Format(time.RFC3339Nano)
	tx := &Transaction{
		Id:              deriveTxID(req),
		FromAccountId:   req.FromAccountId,
		ToAccountId:     req.ToAccountId,
		Amount:          &Money{Currency: req.Amount.Currency, Units: req.Amount.Units, Nanos: req.Amount.Nanos},
		CreatedAtRfc3339: now,
	}

	if req.IdempotencyKey != "" {
		s.idem[req.IdempotencyKey] = tx
	}

	return &CreateTransactionResponse{Transaction: tx}, nil
}

func (s *ledgerServer) GetBalance(ctx context.Context, req *GetBalanceRequest) (*GetBalanceResponse, error) {
	if req == nil {
		return nil, status.Error(codes.InvalidArgument, "request is required")
	}
	if req.AccountId == "" {
		return nil, status.Error(codes.InvalidArgument, "account_id is required")
	}
	if req.Currency == "" {
		return nil, status.Error(codes.InvalidArgument, "currency is required")
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	nanos := s.getBalLocked(req.AccountId, req.Currency)
	return &GetBalanceResponse{
		AccountId: req.AccountId,
		Balance:   nanosToMoney(req.Currency, nanos),
	}, nil
}

func (s *ledgerServer) getBalLocked(account, currency string) int64 {
	if _, ok := s.balances[account]; !ok {
		s.balances[account] = make(map[string]int64)
	}
	return s.balances[account][currency]
}

func (s *ledgerServer) setBalLocked(account, currency string, nanos int64) {
	if _, ok := s.balances[account]; !ok {
		s.balances[account] = make(map[string]int64)
	}
	s.balances[account][currency] = nanos
}

func validateMoney(m *Money) error {
	if m.Nanos <= -1_000_000_000 || m.Nanos >= 1_000_000_000 {
		return errors.New("nanos out of range")
	}
	if m.Units == 0 && m.Nanos == 0 {
		return errors.New("amount must be non-zero")
	}
	total := moneyToNanos(m)
	if total <= 0 {
		return errors.New("amount must be positive")
	}
	return nil
}

func moneyToNanos(m *Money) int64 {
	return m.Units*1_000_000_000 + int64(m.Nanos)
}

func nanosToMoney(currency string, nanos int64) *Money {
	units := nanos / 1_000_000_000
	rem := nanos % 1_000_000_000
	return &Money{
		Currency: currency,
		Units:    units,
		Nanos:    int32(rem),
	}
}

func deriveTxID(req *CreateTransactionRequest) string {
	h := sha256.New()
	h.Write([]byte(req.IdempotencyKey))
	h.Write([]byte{0})
	h.Write([]byte(req.FromAccountId))
	h.Write([]byte{0})
	h.Write([]byte(req.ToAccountId))
	h.Write([]byte{0})
	h.Write([]byte(req.Amount.Currency))
	h.Write([]byte{0})
	h.Write([]byte(fmt.Sprintf("%d:%d", req.Amount.Units, req.Amount.Nanos)))
	sum := h.Sum(nil)
	return hex.EncodeToString(sum[:16])
}

